function validate(args, output) {
    const s = args[0];
    const freq = {};
    for (const ch of s) freq[ch] = (freq[ch] || 0) + 1;
    const groups = {};
    for (const ch in freq) {
        const k = freq[ch];
        if (!groups[k]) groups[k] = [];
        groups[k].push(ch);
    }
    let bestK = null, bestSize = -1;
    for (const kStr in groups) {
        const k = parseInt(kStr, 10);
        const sz = groups[k].length;
        if (sz > bestSize || (sz === bestSize && k > bestK)) { bestSize = sz; bestK = k; }
    }
    const correct = new Set(bestK === null ? [] : groups[bestK]);
    if (typeof output !== 'string') return false;
    const out = output.split('');
    if (out.length !== new Set(out).size) return false;
    if (out.length !== correct.size) return false;
    for (const ch of out) if (!correct.has(ch)) return false;
    return true;
}

