        from collections import Counter
        freq = Counter(s)
        groups = {}
        for ch, k in freq.items():
            groups.setdefault(k, []).append(ch)
        best_k = None
        best_size = -1
        for k in sorted(groups.keys()):
            sz = len(groups[k])
            if sz > best_size or (sz == best_size and (best_k is None or k > best_k)):
                best_size = sz
                best_k = k
        chars = sorted(groups[best_k]) if best_k is not None else []
        return ''.join(chars)

